// AEVUM Reporting Dashboard — HTML Report Builder

const data = items[0].json;
const config = data.config;
const rows = data.ga4Data || [];
const totals = data.totals || [];

// === DATEN EXTRAHIEREN ===
// GA4 gibt Totals als erstes Totals-Item (aktuelle Periode) und zweites (Vergleich)
const currentTotals = totals[0]?.metricValues || [];
const prevTotals = totals[1]?.metricValues || [];

const currentSessions = parseInt(currentTotals[0]?.value || 0);
const prevSessions = parseInt(prevTotals[0]?.value || 0);
const currentConversions = parseInt(currentTotals[1]?.value || 0);
const prevConversions = parseInt(prevTotals[1]?.value || 0);

const convRate = currentSessions > 0 ? ((currentConversions / currentSessions) * 100).toFixed(2) : 0;
const prevConvRate = prevSessions > 0 ? ((prevConversions / prevSessions) * 100).toFixed(2) : 0;

// Deltas berechnen
const sessionDelta = prevSessions > 0 ? Math.round(((currentSessions - prevSessions) / prevSessions) * 100) : 0;
const convDelta = prevConversions > 0 ? Math.round(((currentConversions - prevConversions) / prevConversions) * 100) : 0;
const convRateDelta = (convRate - prevConvRate).toFixed(2);

// Top 5 Seiten
const topPages = rows.slice(0, 5).map(row => ({
  page: row.dimensionValues?.[0]?.value || '/',
  sessions: parseInt(row.metricValues?.[0]?.value || 0)
}));

// Performance-Ampel
let statusColor = '#27ae60'; // Grün
let statusText = 'Gut';
if (convRate < 0.5 || sessionDelta < -20) {
  statusColor = '#e74c3c'; // Rot
  statusText = 'Handlungsbedarf';
} else if (convRate < 1.0 || sessionDelta < -10) {
  statusColor = '#f39c12'; // Gelb
  statusText = 'Beobachten';
}

// Delta-Farbe Helfer
const deltaColor = (val) => val >= 0 ? '#27ae60' : '#e74c3c';
const deltaSign = (val) => val >= 0 ? '+' : '';

// === HTML REPORT BAUEN ===
const topPagesRows = topPages.map((p, i) => 
  `<tr style="border-bottom:1px solid #eee;"><td style="padding:6px 12px;color:#666;">${i+1}.</td><td style="padding:6px 12px;font-family:monospace;font-size:13px;">${p.page}</td><td style="padding:6px 12px;text-align:right;font-weight:600;">${p.sessions.toLocaleString('de-DE')}</td></tr>`
).join('');

const html = `<!DOCTYPE html>
<html>
<head><meta charset="UTF-8"><title>${config.reportTitle}</title></head>
<body style="font-family: -apple-system, BlinkMacSystemFont, 'Segoe UI', sans-serif; background:#f5f5f5; margin:0; padding:20px;">

<div style="max-width:600px; margin:0 auto;">

  <!-- Header -->
  <div style="background:#1a1a2e; color:white; padding:24px 30px; border-radius:12px 12px 0 0;">
    <h1 style="margin:0; font-size:20px; font-weight:700;">📊 ${config.reportTitle}</h1>
    <p style="margin:6px 0 0; color:#aaa; font-size:14px;">${config.weekLabel}</p>
  </div>

  <!-- KPI Grid -->
  <div style="background:white; padding:24px 30px; display:flex; gap:16px; flex-wrap:wrap;">

    <div style="flex:1; min-width:120px; background:#f8f9fa; border-radius:8px; padding:16px; text-align:center;">
      <div style="font-size:24px; font-weight:700; color:#1a1a2e;">${currentSessions.toLocaleString('de-DE')}</div>
      <div style="font-size:12px; color:#666; margin-top:4px;">Sessions</div>
      <div style="font-size:13px; color:${deltaColor(sessionDelta)}; margin-top:4px; font-weight:600;">${deltaSign(sessionDelta)}${sessionDelta}%</div>
    </div>

    <div style="flex:1; min-width:120px; background:#f8f9fa; border-radius:8px; padding:16px; text-align:center;">
      <div style="font-size:24px; font-weight:700; color:#1a1a2e;">${currentConversions.toLocaleString('de-DE')}</div>
      <div style="font-size:12px; color:#666; margin-top:4px;">Conversions</div>
      <div style="font-size:13px; color:${deltaColor(convDelta)}; margin-top:4px; font-weight:600;">${deltaSign(convDelta)}${convDelta}%</div>
    </div>

    <div style="flex:1; min-width:120px; background:#f8f9fa; border-radius:8px; padding:16px; text-align:center;">
      <div style="font-size:24px; font-weight:700; color:#1a1a2e;">${convRate}%</div>
      <div style="font-size:12px; color:#666; margin-top:4px;">Conv. Rate</div>
      <div style="font-size:13px; color:${deltaColor(parseFloat(convRateDelta))}; margin-top:4px; font-weight:600;">${deltaSign(parseFloat(convRateDelta))}${convRateDelta}pp</div>
    </div>

    <div style="flex:1; min-width:120px; background:${statusColor}22; border:2px solid ${statusColor}; border-radius:8px; padding:16px; text-align:center;">
      <div style="font-size:18px; font-weight:700; color:${statusColor};">● ${statusText}</div>
      <div style="font-size:12px; color:#666; margin-top:4px;">Status</div>
    </div>

  </div>

  <!-- Top Seiten -->
  <div style="background:white; border-top:1px solid #eee; padding:24px 30px;">
    <h3 style="margin:0 0 12px; font-size:15px; color:#1a1a2e;">Top Seiten (nach Sessions)</h3>
    <table style="width:100%; border-collapse:collapse;">
      ${topPagesRows}
    </table>
  </div>

  <!-- Footer -->
  <div style="background:#f8f9fa; padding:16px 30px; border-radius:0 0 12px 12px; font-size:12px; color:#999; border-top:1px solid #eee;">
    Automatisch generiert von AEVUM Reporting · ${new Date().toLocaleDateString('de-DE')} · Konfiguriert in n8n
  </div>

</div>
</body></html>`;

return [{
  json: {
    html,
    subject: `${config.reportTitle} — ${config.weekLabel}`,
    recipients: config.reportRecipients,
    stats: { currentSessions, currentConversions, convRate, statusText }
  }
}];
